        val nextSibling = operationReference.nextSibling() ?: return false
        val nextSiblingFirstLeaf = nextSibling.firstChildLeafOrSelf()

        // Look for whitespace before the next sibling
        var node = nextSiblingFirstLeaf
        while (node != null && node != operationReference) {
            if (node.textContains('\n')) {
                // The right-hand side is already on a new line, so wrapping after the elvis operator
                // would cause the line to end with the elvis operator
                return true
            }
            node = node.prevLeaf()
        }

        return false
    }"}

